// ─── Prospector Gmail Send Gate ────────────────────────────────────────────
// Enforces: payload validation, time window, daily cap, 5-min stagger.
// Static data persists across executions in the same workflow.

const DAILY_CAP = 30;           // Conservative warm-up cap. Override via N8N_GLV_DAILY_CAP env.
const STAGGER_MINUTES = 5;      // Min minutes between sends.
const TZ_OFFSET_ET = -4;        // EDT (UTC-4). Adjust to -5 in EST winter.
const SEND_WINDOW_START = 9;    // 9am ET
const SEND_WINDOW_END = 18;     // 6pm ET
const SEND_DAYS = [1,2,3,4,5];  // Mon-Fri (0=Sun)

const body = $input.first().json.body ?? $input.first().json;
const { to, subject, body_html, metadata = {} } = body;

// ── 1. Payload validation ──────────────────────────────────────────────────
if (!to || !subject || !body_html) {
  return [{ json: { proceed: false, reason: 'missing_fields', detail: 'to, subject, and body_html are required', metadata } }];
}
if (typeof to !== 'string' || !to.includes('@')) {
  return [{ json: { proceed: false, reason: 'invalid_to', detail: 'to must be a valid email address', metadata } }];
}

// ── 2. Time window gate (9am–6pm ET, Mon–Fri) ─────────────────────────────
const now = new Date();
const etHour = (now.getUTCHours() + 24 + TZ_OFFSET_ET) % 24;
const etDay = new Date(now.getTime() + TZ_OFFSET_ET * 3600000).getUTCDay();
const inWindow = SEND_DAYS.includes(etDay) && etHour >= SEND_WINDOW_START && etHour < SEND_WINDOW_END;
if (!inWindow) {
  const nextMonday = etDay === 0 ? 1 : etDay === 6 ? 2 : 0; // rough next open slot
  return [{ json: { proceed: false, reason: 'outside_send_window', detail: `Current ET hour: ${etHour}, day: ${etDay}. Window: 9am–6pm ET Mon–Fri.`, queued_suggestion: 'Retry after next send window opens.', metadata } }];
}

// ── 3. Daily cap check ────────────────────────────────────────────────────
const staticData = $getWorkflowStaticData('global');
const todayDate = now.toISOString().slice(0, 10);
if (staticData.dailySends?.date !== todayDate) {
  staticData.dailySends = { date: todayDate, count: 0 };
}
const effectiveCap = parseInt(process.env.N8N_GLV_DAILY_CAP ?? String(DAILY_CAP));
if (staticData.dailySends.count >= effectiveCap) {
  return [{ json: { proceed: false, reason: 'daily_cap_reached', detail: `${staticData.dailySends.count}/${effectiveCap} emails sent today. Cap resets tomorrow.`, metadata } }];
}

// ── 4. Stagger check (5 min between sends) ────────────────────────────────
const lastSendMs = staticData.lastSendMs ?? 0;
const msSinceLast = now.getTime() - lastSendMs;
const staggerMs = STAGGER_MINUTES * 60 * 1000;
if (msSinceLast < staggerMs) {
  const waitSec = Math.ceil((staggerMs - msSinceLast) / 1000);
  return [{ json: { proceed: false, reason: 'stagger_wait', detail: `Last send was ${Math.round(msSinceLast/1000)}s ago. Min stagger: ${STAGGER_MINUTES}min. Retry in ${waitSec}s.`, retry_after_seconds: waitSec, metadata } }];
}

// ── All gates passed ──────────────────────────────────────────────────────
return [{ json: { proceed: true, to, subject, body_html, metadata, et_hour: etHour, daily_count: staticData.dailySends.count, cap: effectiveCap } }];

// Update stagger + daily count after successful send.
const staticData = $getWorkflowStaticData('global');
const todayDate = new Date().toISOString().slice(0, 10);
if (staticData.dailySends?.date !== todayDate) {
  staticData.dailySends = { date: todayDate, count: 0 };
}
staticData.dailySends.count += 1;
staticData.lastSendMs = Date.now();

// Pass through Gmail node output + enrich
const gmailOut = $input.first().json;
return [{ json: {
  status: 'sent',
  message_id: gmailOut.id ?? gmailOut.messageId ?? null,
  thread_id: gmailOut.threadId ?? null,
  sent_at: new Date().toISOString(),
  daily_count: staticData.dailySends.count,
  metadata: $('Validate + Gate (time, cap, stagger)').first().json.metadata ?? {}
}}];
